def count_numbers_with_1_at_edges(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    count = 2 * (10 ** (n - 1))
    if n > 1:
        count -= 2  # Adjust for overlap of numbers starting and ending with 1
    return count

def count_numbers_start_or_end_with_1(n):
    count = 0
    start = 10**(n-1)
    end = 10**n
    for num in range(start, end):
        str_num = str(num)
        if str_num.startswith('1') or str_num.endswith('1'):
            count += 1
    return count

