from typing import List

class Solution:
    def findPrimePairs(self, n: int) -> List[List[int]]:
        def is_prime(num):
            if num <= 1:
                return False
            if num == 2:
                return True
            if num % 2 == 0:
                return False
            for i in range(3, int(num**0.5) + 1, 2):
                if num % i == 0:
                    return False
            return True

        prime_pairs = []
        for i in range(2, n // 2 + 1):
            if is_prime(i) and is_prime(n - i):
                prime_pairs.append((i, n - i))

